class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        if len(s1) > len(s2): return False
        need = [0]*26
        win = [0]*26
        for c in s1: need[ord(c)-97] += 1
        for i, c in enumerate(s2):
            win[ord(c)-97] += 1
            if i >= len(s1):
                win[ord(s2[i-len(s1)])-97] -= 1
            if i >= len(s1)-1:
                if win == need: return True
        return False

